class Solution:
    def threeSumMulti(self, arr, target: int) -> int:
        MOD = 10**9 + 7
        n = len(arr)
        count = 0
        for i in range(n):
            for j in range(i + 1, n):
                for kk in range(j + 1, n):
                    if arr[i] + arr[j] + arr[kk] == target:
                        count += 1
        return count % MOD

