class Solution:
    def threeSumMulti(self, arr, target: int) -> int:
        MOD = 10**9 + 7
        from collections import Counter
        cnt = Counter(arr)
        keys = sorted(cnt)
        ans = 0
        for i, a in enumerate(keys):
            for j in range(i, len(keys)):
                b = keys[j]
                c = target - a - b
                if c < b or c not in cnt:
                    continue
                if a == b == c:
                    ans += cnt[a] * (cnt[a]-1) * (cnt[a]-2) // 6
                elif a == b:
                    ans += cnt[a] * (cnt[a]-1) // 2 * cnt[c]
                elif b == c:
                    ans += cnt[a] * cnt[b] * (cnt[b]-1) // 2
                else:
                    ans += cnt[a] * cnt[b] * cnt[c]
        return ans % MOD

