var threeSumMulti = function(arr, target) {
    const MOD = 1000000007n;
    const cnt = new Array(101).fill(0);
    for (const x of arr) cnt[x]++;
    let ans = 0n;
    for (let a = 0; a <= 100; a++) {
        for (let b = a; b <= 100; b++) {
            const c = target - a - b;
            if (c < b || c > 100 || cnt[c] === 0) continue;
            let ways;
            if (a === b && b === c) {
                ways = BigInt(cnt[a]) * BigInt(cnt[a] - 1) * BigInt(cnt[a] - 2) / 6n;
            } else if (a === b) {
                ways = BigInt(cnt[a]) * BigInt(cnt[a] - 1) / 2n * BigInt(cnt[c]);
            } else if (b === c) {
                ways = BigInt(cnt[a]) * BigInt(cnt[b]) * BigInt(cnt[b] - 1) / 2n;
            } else {
                ways = BigInt(cnt[a]) * BigInt(cnt[b]) * BigInt(cnt[c]);
            }
            ans = (ans + ways) % MOD;
        }
    }
    return Number(ans);
};
